  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isDark = location.pathname === '/vault';

  return (
    <nav className={`fixed top-0 left-0 w-full z-40 transition-all duration-700 ${scrolled ? 'bg-black/80 backdrop-blur-md border-b border-white/5 py-4' : 'bg-transparent py-8'}`}>
      <div className="max-w-[1800px] mx-auto px-6 md:px-12 flex justify-between items-center">
        <div className="flex items-center gap-10">
          <button onClick={onOpenMenu} className="text-white hover:text-[#D4AF37] transition-all duration-300 transform active:scale-95">
            <Menu size={26} strokeWidth={1} />
          </button>
          <Link to="/" className="text-xl md:text-2xl font-black tracking-[0.4em] hover:opacity-70 transition-opacity">
            DSTRKT
          </Link>
        </div>

        <div className="hidden lg:flex gap-16 text-[10px] tracking-[0.4em] font-bold uppercase items-center">
          <Link to="/" className={`hover:text-[#D4AF37] transition-colors relative group ${location.pathname === '/' ? 'text-[#D4AF37]' : 'text-white/60'}`}>
            Collection
            <span className="absolute -bottom-2 left-0 w-0 h-[1px] bg-[#D4AF37] group-hover:w-full transition-all duration-300"></span>
          </Link>
          <Link to="/vault" className={`hover:text-[#D4AF37] transition-colors relative group ${location.pathname === '/vault' ? 'text-[#D4AF37]' : 'text-white/60'}`}>
            The Vault
            <span className="absolute -bottom-2 left-0 w-0 h-[1px] bg-[#D4AF37] group-hover:w-full transition-all duration-300"></span>
          </Link>
          <a href="#" className="text-white/60 hover:text-[#D4AF37] transition-colors">Culture</a>
        </div>

        <div className="flex items-center gap-6 md:gap-8">
          <button className="hidden sm:block text-white/40 hover:text-white transition-colors">
            <Search size={20} strokeWidth={1} />
          </button>
          <button className="hidden sm:flex items-center gap-2 text-[10px] tracking-[0.2em] font-bold text-white/40 hover:text-white transition-colors uppercase">
            <Globe size={14} strokeWidth={1.5} /> Region: US
          </button>
          <button className="relative group p-2">
            <ShoppingBag size={22} strokeWidth={1} className="group-hover:text-[#D4AF37] transition-colors" />
            <span className="absolute top-0 right-0 bg-[#D4AF37] text-black text-[9px] font-bold w-4 h-4 rounded-full flex items-center justify-center">2</span>
          </button>
        </div>
      </div>
    </nav>
  );
};

const OverlayMenu: React.FC<{ isOpen: boolean; onClose: () => void }> = ({ isOpen, onClose }) => {
  const menuVariants = {
    closed: { x: '-100%', transition: { duration: 0.8, ease: [0.76, 0, 0.24, 1] } },
    open: { x: 0, transition: { duration: 0.8, ease: [0.76, 0, 0.24, 1] } }
  };

  const itemVariants = {
    closed: { x: -20, opacity: 0 },
    open: i => ({ x: 0, opacity: 1, transition: { delay: 0.4 + i * 0.1, duration: 0.5 } })
  };

  return (
    <motion.div 
      initial="closed"
      animate={isOpen ? "open" : "closed"}
      variants={menuVariants}
      className="fixed inset-0 z-[60] bg-black flex flex-col justify-between p-12 md:p-24"
    >
      <button onClick={onClose} className="absolute top-8 left-8 md:top-12 md:left-12 text-white/60 hover:text-[#D4AF37] transition-colors">
        <X size={32} strokeWidth={1} />
      </button>

      <div className="flex flex-col gap-8 mt-12">
        {['Collection', 'The Vault', 'Culture', 'Craftsmanship', 'About'].map((item, i) => (
          <motion.div key={item} custom={i} variants={itemVariants} initial="closed" animate={isOpen ? "open" : "closed"}>
            <Link 
              to={item === 'The Vault' ? '/vault' : '/'} 
              onClick={onClose}
              className="text-5xl md:text-8xl font-black tracking-tighter hover:text-[#D4AF37] transition-colors uppercase"
            >
              {item}
            </Link>
          </motion.div>
        ))}
      </div>

      <div className="flex flex-wrap justify-between items-end border-t border-white/10 pt-12">
        <div className="flex flex-col gap-2">
          <p className="text-[10px] tracking-[0.3em] font-bold text-white/40 uppercase">Connect</p>
          <div className="flex gap-6">
            <Instagram size={20} className="hover:text-[#D4AF37] cursor-pointer" />
            <Twitter size={20} className="hover:text-[#D4AF37] cursor-pointer" />
          </div>
        </div>
