const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

const App: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  return (
    <Router>
      <ScrollToTop />
      <div className="min-h-screen selection:bg-[#D4AF37] selection:text-black">
        <Navbar onOpenMenu={() => setIsMenuOpen(true)} />
        <OverlayMenu isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} />

        <AnimatePresence mode="wait">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/vault" element={<Vault />} />
            <Route path="/product/:id" element={<ProductDetail />} />
          </Routes>
        </AnimatePresence>

        <Footer />
      </div>
    </Router>
  );
};

export default App;

import React from 'react';
import { motion } from 'framer-motion';
import { VAULT_DROPS } from './constants';
import { Lock, Clock, Info } from 'lucide-react';

const VaultItem: React.FC<{ drop: any, index: number }> = ({ drop, index }) => {
  const isUpcoming = drop.status === 'upcoming';
  const isSoldOut = drop.status === 'sold-out';

  return (
    <motion.div 
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.1, duration: 0.8 }}
      className="group"
    >
      <div className="relative aspect-[4/5] bg-[#0d0d0d] overflow-hidden mb-8 border border-white/5 gold-glow transition-all duration-500">
        <img 
          src={drop.image} 
          alt={drop.name} 
          className={`w-full h-full object-cover transition-transform duration-[4s] group-hover:scale-110 ${isSoldOut ? 'grayscale opacity-30' : 'grayscale group-hover:grayscale-0'}`}
        />

        <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-80"></div>

        {isSoldOut && (
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-[10px] tracking-[0.8em] font-black text-white/40 uppercase rotate-[-45deg] border-2 border-white/10 px-8 py-2">Sold Out</span>
          </div>
        )}

        <div className="absolute top-8 right-8">
          {isUpcoming ? (
            <div className="flex items-center gap-2 bg-[#D4AF37] text-black px-4 py-2 rounded-full text-[9px] font-black tracking-widest">
              <Clock size={12} /> DROPS SOON
            </div>
          ) : !isSoldOut && (
            <div className="flex items-center gap-2 bg-white text-black px-4 py-2 rounded-full text-[9px] font-black tracking-widest">
              <Lock size={12} /> ACTIVE
            </div>
          )}
        </div>

        <div className="absolute bottom-8 left-8 right-8">
          <p className="text-[10px] tracking-[0.4em] font-bold text-[#D4AF37] mb-2 uppercase">{drop.status.replace('-', ' ')}</p>
          <h4 className="text-2xl font-black uppercase tracking-tighter mb-4">{drop.name}</h4>
          <p className="text-[11px] text-white/60 leading-relaxed font-light line-clamp-2">{drop.description}</p>
        </div>
      </div>

      {!isSoldOut && (
        <button className={`w-full py-5 text-[10px] tracking-[0.4em] font-black uppercase transition-all duration-500 border border-white/10 hover:border-[#D4AF37] ${isUpcoming ? 'bg-transparent text-white' : 'bg-[#D4AF37] text-black'}`}>
          {isUpcoming ? 'Join Waiting List' : 'Enter Private Shop'}
        </button>
      )}
    </motion.div>
  );
};

