      <div className="max-w-[1800px] mx-auto px-6 md:px-12 relative z-10">
        <Link to="/vault" className="inline-flex items-center gap-4 text-[10px] tracking-[0.5em] font-black uppercase text-white/40 hover:text-[#D4AF37] mb-20 transition-colors group">
          <ArrowLeft size={16} className="group-hover:-translate-x-2 transition-transform" /> Exit Private Shop
        </Link>

        <header className="mb-32">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
