                            id: drop.id,
                            name: drop.name,
                            price: "$1,450", 
                            description: drop.description,
                            image: drop.image,
                            tag: 'VAULT'
                          }, 1)}
                          className="px-10 py-5 bg-white text-black hover:bg-[#D4AF37] text-[10px] tracking-[0.4em] font-black uppercase transition-all flex items-center gap-3"
                        >
                          <ShoppingBag size={14} /> Add to Bag
                        </button>
                        <Link to={`/product/${drop.id}`}>
                          <button className="text-[9px] tracking-[0.5em] font-black uppercase text-white/60 hover:text-white transition-colors flex items-center gap-2">
                            <Eye size={12} /> {drop.id === 'v2' ? 'View Duffel' : 'View Schematics'}
                          </button>
                        </Link>
                      </div>
                    )}

                    <div className="absolute top-8 left-8">
                      <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-[#D4AF37] shadow-[0_0_15px_#D4AF37]' : isSoldOut ? 'bg-white/20' : 'bg-white/40 animate-pulse'}`}></div>
                    </div>

                    <div className="absolute top-8 right-8">
                      <p className="text-[8px] tracking-[0.4em] font-black text-white/20 uppercase font-mono">CODE: {drop.id.toUpperCase()}</p>
                    </div>
                  </div>

                  <div className="space-y-4 px-2">
                    <div className="flex justify-between items-start">
                      <div>
                        <p className={`text-[10px] tracking-[0.4em] font-black uppercase mb-1 ${isActive ? 'text-[#D4AF37]' : 'text-white/20'}`}>
                          {drop.status.replace('-', ' ')}
                        </p>
                        <h3 className="text-2xl font-black uppercase tracking-tighter text-white italic group-hover:text-[#D4AF37] transition-colors">{drop.name}</h3>
                      </div>
                      <p className="text-xl font-black text-white/80">$1,450</p>
                    </div>
                    <p className="text-[11px] text-white/30 leading-relaxed uppercase tracking-widest font-bold line-clamp-2">
                      {drop.description}
                    </p>
                  </div>
                </motion.div>
              );
            })}
          </AnimatePresence>
        </div>

        {/* Exclusive Footer */}
        <section className="mt-60 py-40 border-t border-white/5 text-center bg-[#070707] -mx-12 px-12">
          <Lock size={48} className="text-[#D4AF37] mx-auto mb-12 animate-pulse" strokeWidth={1} />
          <h2 className="text-4xl md:text-8xl font-black uppercase tracking-tighter italic mb-8">End of Session.</h2>
          <p className="text-white/30 text-[10px] tracking-[0.6em] font-black uppercase max-w-2xl mx-auto leading-loose border-y border-white/5 py-12">
            The Private Shop contains strictly non-public inventory. All digital signatures are tracked and unique to your membership ID. Do not share access links.
          </p>
        </section>
      </div>
    </main>
